sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.dashboard-shortcut{

    background:white;
    margin:40px;
    padding:40px;
    border-radius:12px;
    text-align:center;
    box-shadow:0 8px 18px rgba(0,0,0,.08);

}

.dashboard-shortcut h2{

    color:#0F4C81;
    margin-bottom:15px;

}

.dashboard-shortcut p{

    color:#666;
    margin-bottom:25px;

}

.dashboard-btn{

    display:inline-block;
    background:#0F4C81;
    color:white;
    text-decoration:none;
    padding:14px 30px;
    border-radius:8px;
    font-weight:bold;

}

.dashboard-btn:hover{

    background:#0B3A62;
    color:white;
    text-decoration:none;

}
